// Função para converter nanosegundos para ISO string
function convertNanosToISO(nanosStr) {
    if (!nanosStr) return null;
    const nanos = BigInt(nanosStr);
    const millis = nanos / 1000000n;
    return new Date(Number(millis)).toISOString();
}

